+// Data helpers
+func (m *Model) sortAndFilter(rows []model.Process) []model.Process {
+	// filter
+	filtered := rows
+	if m.filter != "" {
+		filtered = filtered[:0]
+		for _, r := range rows {
+			if strings.Contains(strings.ToLower(r.Command), strings.ToLower(m.filter)) {
+				filtered = append(filtered, r)
+			}
+		}
+	}
+	// sort
+	switch m.sortKey {
+	case "mem":
+		sort.Slice(filtered, func(i, j int) bool { return filtered[i].Memory > filtered[j].Memory })
+	default:
+		sort.Slice(filtered, func(i, j int) bool { return filtered[i].CPU > filtered[j].CPU })
+	}
+	return filtered
+}
+
+func limitProcs(rows []model.Process, n int) []model.Process {
+	if len(rows) <= n {
+		return rows
+	}
+	return rows[:n]
+}
+
+func (m *Model) recordPerCore(per []float64) {
+	for i, v := range per {
+		buf := m.perCoreHist[i]
+		buf = append(buf, v)
+		if len(buf) > 60 {
+			buf = buf[len(buf)-60:]
+		}
+		m.perCoreHist[i] = buf
+	}
+}
+
+func sparkline(values []float64, width int) string {
+	if len(values) == 0 {
+		return ""
+	}
+	if len(values) > width {
+		values = values[len(values)-width:]
+	}
+	blocks := []rune("▁▂▃▄▅▆▇█")
+	var b strings.Builder
+	for _, v := range values {
+		level := int((v / 100) * float64(len(blocks)-1))
+		if level < 0 {
+			level = 0
+		}
+		if level >= len(blocks) {
+			level = len(blocks) - 1
+		}
+		b.WriteRune(blocks[level])
+	}
+	return b.String()
+}
+
+func (m *Model) maybeWriteJSON(s model.Sample) {
+	if m.jsonFile == "" {
+		return
+	}
+	f, err := os.OpenFile(m.jsonFile, os.O_CREATE|os.O_APPEND|os.O_WRONLY, 0644)
+	if err != nil {
+		return
+	}
+	defer f.Close()
+	enc := json.NewEncoder(f)
+	_ = enc.Encode(s)
+}
+
+func displayFilter(m *Model) string {
+	if m.inputMode {
+		return "/" + string(m.inputBuf)
+	}
+	return m.filter
+}
